VALUES
  ('heelevel3-7c4986e7-moex-00085', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司X3年平均應收帳款與平均存貨分別為$120,000與$50,000，當年度銷貨收入為$1,200,000， 銷貨毛利為$300,000，如果一年以360天計算，請問甲公司營業週期天數為何？', '["36天", "56天", "60天", "96天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00086', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X4年初以$120,000購入一專利權，經評估其經濟效益年限為8年，其法定有效年限為 15年。X7年初此專利權蒙受重大損害，經判定專利權不再具有經濟效益。請問甲公司X7年度此 專利權之攤銷費用為何？', '["$96,000", "$75,000", "$15,000", "$0"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00087', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司給予員工每年 20 天之累積制帶薪年休假，未使用之休假天數可遞延 1 年使用，未使用之 剩餘休假並無現金補償。X5年底甲公司有100名員工，X5年平均每名員工已使用15天帶薪年 休假，估計平均每位員工日薪為$1,000。假設員工休假時將優先扣抵前 1 年度所遞延之剩餘休假 天數，再使用當年度之休假天數。請問X5年底甲公司應認列之休假福利負債金額為何？', '["$2,500,000", "$2,000,000", "$500,000", "$0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00088', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司X6年初帳上有5%、每股面額$100之累積特別股20,000股，另有普通股1月1日流通在 外400,000股、4月1日現金增資發行新股100,000股、7月1日買回庫藏股20,000，10月1日再 出售全部庫藏股，X6年度淨利為$1,040,000，惟X6年度甲公司並未宣告特別股股利。請問甲公 司X6年度之每股盈餘為：', '["$1.88", "$2.0", "$2.25", "$2.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00089', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年初以$1,000,000購入耐用10年，估計殘值為$100,000之設備，採直線法折舊。X4 年 8 月初該公司決定修正折舊方法為年數合計法，並估計全部耐用年限共計 8 年，估計殘值為 $70,000。請問X4年度之折舊費用為：', '["$220,000", "$165,000", "$112,500", "$82,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00090', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列何者不屬於其他綜合損益項目？', '["現金流量避險中屬有效避險部分之避險工具利益及損失", "重估增值之變動", "國外營運機構財務報表換算之兌換差額", "確定福利計畫修正所產生之前期服務成本 31940"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00091', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '財務資訊對經濟現象的描述，能讓各獨立且具充分認知的經濟現象觀察者，達成上述經濟現象的 描述為忠實表述的共識。請問上述為財務報導觀念性架構中財務資訊的那一項品質特性？', '["確認價值", "忠實表述", "可驗證性", "可比性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00092', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司 X1 年度之期初存貨$2,080，進貨$19,000，進貨退出$640，進貨運費$764，期初存貨之零 售價$3,200，進貨之零售價$32,000，進貨退出零售價$1,000，銷貨$31,400，銷貨運費$2,000，銷貨 退出$1,400。該公司採用平均成本零售價法，若期末實地盤點存貨之零售價為$1,200，則存貨短絀 數（成本）為多少？', '["$4,200", "$3,000", "$2,604", "$1,860"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00093', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X3年11月1日購買價值$780,000的油井設備。該設備使用年限為5年，屆時設備無任 何殘值。5年後拆除該設備的預計成本為$300,000。假定折現率為8%。試問X3年針對該交易事 項，綜合損益表上共應認列多少費用？（折現率8%，期數5期，$1複利之現值為0.6806）', '["$49,140", "$35,528", "$32,806", "$24,502"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00094', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-113-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司X1年5月8日以現金$875,000取得乙公司50,000股的普通股，甲公司這項投資對乙公司 未具重大影響力，並將該項投資分類為「透過其他綜合損益按公允價值衡量之權益工具投資」。X1 年底與X2年底乙公司普通股收盤價分別為每股$19及$17。請問甲公司X1年底與X2年底之會 計處理下列何者正確？', '["X2年底貸：透過其他綜合損益按公允價值衡量之權益工具投資評價調整$50,000", "X2年底借：其他綜合損益—透過其他綜合損益按公允價值衡量投資未實現損益-股票$10,000", "X1年底貸：其他綜合損益—透過其他綜合損益按公允價值衡量投資未實現損益-股票$75,000", "X1年底借：透過其他綜合損益按公允價值衡量之權益工具投資評價調整$100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:25+00:00", "source_pdf_sha1": "f6f4e5b40e50", "answer_pdf_sha1": "5c1716de8dfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "319", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
